        return errorResponse(
          'unsupported_file_type',
          `Unsupported file type: ${mimeType}. Allowed: images (PNG, JPG, GIF, WebP), HTML mocks, videos, PDF, text files`
        );
      }

      try {
        // Auto-detect evidence type from MIME
        const detectedType = evidenceType || (
          mimeType.startsWith('image/') ? 'screenshot' :
          mimeType.startsWith('video/') ? 'video' :
          mimeType === 'text/plain' ? 'log' :
          mimeType === 'application/json' ? 'test_result' :
          'other'
        );

        // Get feature and validate criteria exists
        const feature = await stateManager.getFeature(featureId);
        if (!feature) {
          return errorResponse('feature_not_found', `Feature ${featureId} not found`);
        }

        const criterion = feature.acceptanceCriteria.find(c => c.id === criteriaId);
        if (!criterion) {
          return errorResponse('criteria_not_found', `Criterion ${criteriaId} not found in feature ${featureId}`);
        }

        // Get task and epic for organization info
        const task = await stateManager.getTask(feature.taskId);
        if (!task) {
          return errorResponse('task_not_found', `Task for feature ${featureId} not found`);
        }
        const epic = await stateManager.getEpic(task.epicId);
        if (!epic) {
          return errorResponse('epic_not_found', `Epic for feature ${featureId} not found`);
        }

        // Generate unique ID for this expected evidence
        const expectedEvidenceId = `exp-${Date.now()}-${Math.random().toString(36).substring(2, 8)}`;

        // Upload file to storage with 'expected' prefix
        const storage = getEvidenceStorage();
        const sanitizedFilename = filename.replace(/[^a-zA-Z0-9._-]/g, '_').substring(0, 255);
        const fileMetadata = await storage.upload({
          organizationId: epic.organizationId,
          featureId,
          submissionId: `expected-${expectedEvidenceId}`,
          filename: sanitizedFilename,
          mimeType,
          content: fileContent,
        });

        // Create the expected evidence entry (only include diffThreshold if defined)
        const expectedEvidence: ExpectedEvidence = {
          id: expectedEvidenceId,
          type: detectedType as EvidenceType,
          description,
          required: isRequired,
          referenceUrl: fileMetadata.url,
          ...(diffThreshold !== undefined && { diffThreshold }),
        };

        // Update the criterion with the new expected evidence
        const updatedCriteria = feature.acceptanceCriteria.map(c => {
          if (c.id === criteriaId) {
            return {
              ...c,
              expectedEvidence: [...(c.expectedEvidence || []), expectedEvidence],
            };
          }
          return c;
        });

        // Update the feature
        await stateManager.updateFeature(featureId, {
          acceptanceCriteria: updatedCriteria,
        });

        // Notify via WebSocket - get updated feature and broadcast
        const updatedFeature = await stateManager.getFeature(featureId);
        if (updatedFeature) {
          wsHandler.broadcastFeatureUpdate(sessionId, updatedFeature);
        }

        return jsonResponse({
          expected_evidence: {
            id: expectedEvidenceId,
            type: detectedType,
            description,
            required: isRequired,
            reference_url: fileMetadata.url,
            diff_threshold: diffThreshold,
          },
          file: {
            path: fileMetadata.path,
            url: fileMetadata.url,
            mime_type: fileMetadata.mimeType,
            size: fileMetadata.size,
            original_filename: sanitizedFilename,
          },
          feature_id: featureId,
          criteria_id: criteriaId,
          message: 'Expected design uploaded successfully',
          upload_mode: base64Content ? 'base64' : 'file_path',
        });
      } catch (error) {
        const errorMessage = error instanceof Error ? error.message : 'Unknown error';
        return errorResponse('upload_expected_design_error', `Failed to upload expected design: ${errorMessage}`);
      }
    }

    case 'add_expected_design_url': {
      const referenceUrl = args.reference_url as string;
      const featureId = args.feature_id as string;
      const criteriaId = args.criteria_id as string;
      const description = args.description as string;
      const evidenceType = (args.evidence_type as string) || 'screenshot';
      const isRequired = args.required !== false;
      const diffThreshold = args.diff_threshold as number | undefined;

      // Validate URL format and prevent SSRF
      try {
        const url = new URL(referenceUrl);

        // SECURITY: Only allow HTTPS (and HTTP for dev/test environments)
        const allowedProtocols = ['https:'];
        if (process.env.NODE_ENV !== 'production') {
          allowedProtocols.push('http:');
        }
        if (!allowedProtocols.includes(url.protocol)) {
          return errorResponse('invalid_protocol', `Protocol ${url.protocol} not allowed. Only HTTPS URLs are permitted.`);
        }

        // SECURITY: Block localhost, private IPs, and cloud metadata endpoints
        const hostname = url.hostname.toLowerCase();
        const isBlocked =
          hostname === 'localhost' ||
          hostname === '127.0.0.1' ||
          hostname === '0.0.0.0' ||
          hostname === '169.254.169.254' || // AWS/GCP metadata
          hostname.startsWith('10.') ||
          hostname.startsWith('192.168.') ||
          /^172\.(1[6-9]|2[0-9]|3[0-1])\./.test(hostname);

        if (isBlocked) {
          return errorResponse('ssrf_blocked', 'URLs to internal/private networks are not allowed');
        }
      } catch {
        return errorResponse('invalid_url', 'Invalid URL format for reference_url');
      }

      try {
        // Get feature and validate criteria exists
        const feature = await stateManager.getFeature(featureId);
        if (!feature) {
          return errorResponse('feature_not_found', `Feature ${featureId} not found`);
        }

        const criterion = feature.acceptanceCriteria.find(c => c.id === criteriaId);
        if (!criterion) {
          return errorResponse('criteria_not_found', `Criterion ${criteriaId} not found in feature ${featureId}`);
        }

        // Generate unique ID for this expected evidence
        const expectedEvidenceId = `exp-${Date.now()}-${Math.random().toString(36).substring(2, 8)}`;

        // Create the expected evidence entry (only include diffThreshold if defined)
        const expectedEvidence: ExpectedEvidence = {
          id: expectedEvidenceId,
          type: evidenceType as EvidenceType,
          description,
          required: isRequired,
          referenceUrl,
          ...(diffThreshold !== undefined && { diffThreshold }),
        };

        // Update the criterion with the new expected evidence
        const updatedCriteria = feature.acceptanceCriteria.map(c => {
          if (c.id === criteriaId) {
            return {
              ...c,
              expectedEvidence: [...(c.expectedEvidence || []), expectedEvidence],
            };
          }
          return c;
        });

        // Update the feature
        await stateManager.updateFeature(featureId, {
          acceptanceCriteria: updatedCriteria,
        });

        // Notify via WebSocket - get updated feature and broadcast
        const updatedFeature = await stateManager.getFeature(featureId);
        if (updatedFeature) {
          wsHandler.broadcastFeatureUpdate(sessionId, updatedFeature);
        }

        return jsonResponse({
          expected_evidence: {
            id: expectedEvidenceId,
            type: evidenceType,
            description,
            required: isRequired,
            reference_url: referenceUrl,
            diff_threshold: diffThreshold,
          },
          feature_id: featureId,
          criteria_id: criteriaId,
          message: 'Expected design URL added successfully',
        });
      } catch (error) {
        const errorMessage = error instanceof Error ? error.message : 'Unknown error';
        return errorResponse('add_expected_design_url_error', `Failed to add expected design URL: ${errorMessage}`);
      }
    }

    default:
      return errorResponse('unknown_tool', `Unknown feature tool: ${name}`);
  }
}

