      }

      let fileContent: Buffer;
      let filename: string;
      let mimeType: string;

      // MIME type mapping (SVG and HTML excluded for security)
      const mimeTypes: Record<string, string> = {
        '.png': 'image/png',
        '.jpg': 'image/jpeg',
        '.jpeg': 'image/jpeg',
        '.gif': 'image/gif',
        '.webp': 'image/webp',
        '.pdf': 'application/pdf',
        '.json': 'application/json',
        '.txt': 'text/plain',
        '.md': 'text/markdown',
      };

      if (base64Content) {
