} from '../../state/types.js';
import { detectCircularDependency } from '../helpers/execution-utils.js';
import { getEvidenceStorage } from '../../state/evidence-storage.js';

import { createLogger } from '../../lib/logger.js';

const log = createLogger('mcp-tools');

// File size limit from environment (default 5MB)
