export const toolNames = definitions.map(d => d.name);

export async function handle(
  name: string,
  args: Record<string, unknown>,
  deps: ToolDependencies
): Promise<ToolResponse> {
  const { stateManager, wsHandler, sessionId } = deps;

  // Validate org ownership before any feature operations
  const orgValidationError = await validateSessionOrgAccess(stateManager, sessionId, getCurrentOrgId());
  if (orgValidationError) {
    return orgValidationError;
  }

  switch (name) {
    case 'update_features': {
      // Session MUST have taskId to create features
      const session = await stateManager.getSession(sessionId);
      if (!session) {
        return errorResponse('session_not_found', `Session ${sessionId} not found`);
      }

      if (!session.epicId) {
        // Fetch available epics to include in error context
        const orgId = getCurrentOrgId();
        let availableEpics: Array<{ id: string; title: string }> = [];
        if (orgId) {
          try {
            const result = await stateManager.listEpicSummariesPaginated(orgId, { limit: 5 });
            availableEpics = result.items.map(e => ({ id: e.id, title: e.title }));
          } catch {
            // Ignore - just won't include context
          }
        }

        return workflowErrorResponse(
          'no_epic_linked',
          'Session must be linked to an Epic before creating features.',
          {
            tool: 'session_init',
            description: 'Initialize session with an Epic',
            example_params: availableEpics.length > 0
              ? { epic_id: availableEpics[0].id }
              : { epic_id: 'EPIC-ID' },
          },
          {
            hint: 'Features live in Epic → Task hierarchy. Link your session to an Epic first.',
            workflow_state: 'needs_epic',
            ...(availableEpics.length > 0 ? { available_epics: availableEpics } : {}),
          }
        );
      }

      if (!session.taskId) {
        // Fetch available tasks from the linked epic
        let availableTasks: Array<{ id: string; title: string }> = [];
        try {
          const tasks = await stateManager.listTasks(session.epicId);
          availableTasks = tasks
            .filter(t => t.status === 'ready')
            .slice(0, 5)
            .map(t => ({ id: t.id, title: t.title }));
        } catch {
          // Ignore - just won't include context
        }

        return workflowErrorResponse(
          'no_task_set',
          'Session must have a claimed task before creating features.',
          {
            tool: 'claim_task',
            description: 'Claim an available task from the Epic',
            example_params: availableTasks.length > 0
              ? { task_id: availableTasks[0].id }
              : { task_id: 'TASK-ID' },
          },
          {
            hint: 'Session has epicId but no taskId. Claim a task from the Epic to proceed.',
            workflow_state: 'needs_task',
            epic_id: session.epicId,
            ...(availableTasks.length > 0 ? { available_tasks: availableTasks } : {}),
          }
        );
      }

      // Verify Epic exists and belongs to the session's org (defense in depth)
      const epic = await stateManager.getEpic(session.epicId);
      if (!epic) {
        return errorResponse('epic_not_found', `Linked Epic ${session.epicId} not found`);
      }
      if (session.organizationId && epic.organizationId !== session.organizationId) {
        log.warn({ sessionOrg: session.organizationId, epicOrg: epic.organizationId }, 'Epic org mismatch');
        return errorResponse('access_denied', 'Session and Epic organization mismatch');
      }

      const featureId = args.feature_id as string;
      const title = args.title as string;
      const description = args.description as string | undefined;
      const acceptanceCriteria = (args.acceptance_criteria as Array<{
        id: string;
        description: string;
        status: string;
      }>).map((c) => ({
        id: c.id,
        description: c.description,
        status: c.status as AcceptanceCriteria['status'],
      }));

      // Parallel execution fields
      const assignedAgent = args.assigned_agent as AgentType | undefined;
      const dependsOn = args.depends_on as string[] | undefined;
      const canParallelize = args.can_parallelize as boolean | undefined;
      const estimatedComplexity = args.estimated_complexity as TaskComplexity | undefined;

      // Check if feature already exists
      const existingFeature = await stateManager.getFeature(featureId);

      // Validate dependencies if provided
      if (dependsOn && dependsOn.length > 0) {
        const existingFeatures = await stateManager.listFeatures(session.taskId);
        const existingIds = new Set(existingFeatures.map(f => f.id));

        // Check that all dependencies exist (or will exist - allow self-referencing batch)
        const missingDeps = dependsOn.filter(depId =>
          depId !== featureId && !existingIds.has(depId)
        );

        if (missingDeps.length > 0) {
          return errorResponse(
            'invalid_dependencies',
            `Dependencies not found: ${missingDeps.join(', ')}`,
            { hint: 'Ensure all dependency features are created before referencing them' }
          );
        }

        // Check for circular dependencies
        const allFeatures = [...existingFeatures];
        const existingIndex = allFeatures.findIndex(f => f.id === featureId);
        const tempFeature = {
          id: featureId,
          title,
          dependsOn,
          status: 'draft' as const,
          acceptanceCriteria: [],
          createdAt: new Date().toISOString(),
          updatedAt: new Date().toISOString(),
          taskId: session.taskId,
          epicId: session.epicId,
        };
        if (existingIndex >= 0) {
          allFeatures[existingIndex] = { ...allFeatures[existingIndex], ...tempFeature };
        } else {
          allFeatures.push(tempFeature);
        }

        const hasCircular = detectCircularDependency(featureId, allFeatures);
        if (hasCircular) {
          return errorResponse(
            'circular_dependency',
            `Circular dependency detected involving feature: ${featureId}`,
            { hint: 'Review the dependency chain to remove the cycle' }
          );
        }
      }

      let feature;
      if (existingFeature) {
        // Update existing feature (preserve status)
        feature = await stateManager.updateFeature(featureId, {
          title,
          description,
          status: existingFeature.status,
          assignedAgent,
          dependsOn,
          canParallelize,
        });
      } else {
        // Create new feature
        feature = await stateManager.createFeature({
          taskId: session.taskId,
          title,
          description,
          acceptanceCriteria: acceptanceCriteria.map(c => ({
            description: c.description,
          })),
          assignedAgent,
          dependsOn,
          canParallelize,
          estimatedComplexity,
        });
      }

      wsHandler.broadcastFeatureUpdate(sessionId, feature);

      return jsonResponse({ success: true, feature });
    }

    case 'verify_feature': {
      const featureId = args.feature_id as string;
      const criteriaId = args.criteria_id as string;
      const verificationType = args.verification_type as string;
      const evidenceText = args.evidence as string;
      const passed = args.passed as boolean;
      const notes = args.notes as string | undefined;
      const evidenceItems = args.evidence_items as Array<{
        type: string;
        title?: string;
        description?: string;
        url?: string;
        base64?: string;
        text?: string;
        mimeType?: string;
      }> | undefined;

      // Parse test_results if provided
      const testResultsInput = args.test_results as {
        framework?: string;
        new_tests: { count: number; names?: string[] };
        existing_tests: { count: number; passed: number; failed: number };
        summary: { total: number; passed: number; failed: number; skipped?: number; duration?: number };
      } | undefined;

      // Convert to TestResults format
      const testResults: TestResults | undefined = testResultsInput ? {
        framework: testResultsInput.framework,
        newTests: {
          count: testResultsInput.new_tests.count,
          names: testResultsInput.new_tests.names,
        },
        existingTests: {
          count: testResultsInput.existing_tests.count,
          passed: testResultsInput.existing_tests.passed,
          failed: testResultsInput.existing_tests.failed,
        },
        summary: {
          total: testResultsInput.summary.total,
          passed: testResultsInput.summary.passed,
          failed: testResultsInput.summary.failed,
          skipped: testResultsInput.summary.skipped ?? 0,
          duration: testResultsInput.summary.duration,
        },
      } : undefined;

      // Build evidence array
      const evidenceArray: Array<{
        type: 'screenshot' | 'video' | 'log' | 'test_result' | 'other';
        title?: string;
        description?: string;
        url?: string;
        base64?: string;
        text?: string;
        mimeType?: string;
        testResults?: TestResults;
      }> = [];

      // Convert legacy evidence string to evidence object
      if (evidenceText) {
        let evidenceType: 'screenshot' | 'video' | 'log' | 'test_result' | 'other' = 'other';
        if (verificationType === 'screenshot') evidenceType = 'screenshot';
        else if (verificationType === 'test_output' || verificationType === 'automated_test') evidenceType = 'test_result';
        else if (verificationType === 'manual_check') evidenceType = 'log';

        const isUrl = evidenceText.startsWith('http://') || evidenceText.startsWith('https://');
        evidenceArray.push({
          type: evidenceType,
          title: `${verificationType} evidence`,
          ...(isUrl ? { url: evidenceText } : { text: evidenceText }),
          ...(testResults && evidenceType === 'test_result' ? { testResults } : {}),
        });
      }

      // Add structured evidence items
      if (evidenceItems && Array.isArray(evidenceItems)) {
        for (const item of evidenceItems) {
          const itemType = item.type as 'screenshot' | 'video' | 'log' | 'test_result' | 'other';
          evidenceArray.push({
            type: itemType,
            title: item.title,
            description: item.description,
            url: item.url,
            base64: item.base64,
            text: item.text,
            mimeType: item.mimeType,
            ...(testResults && itemType === 'test_result' ? { testResults } : {}),
          });
        }
      }

      try {
        const result = await stateManager.verifyFeature({
          featureId,
          criteriaId,
          verificationType: verificationType as 'screenshot' | 'test_output' | 'manual_check' | 'automated_test',
          passed,
          notes,
          evidence: evidenceArray.length > 0 ? evidenceArray : undefined,
        });

        wsHandler.broadcastFeatureUpdate(sessionId, result.feature);

        // Check if all criteria are now passed (feature complete)
        const allPassed = result.feature.acceptanceCriteria.every(c => c.status === 'passed');

        return jsonResponse({
          success: true,
          verification: {
            feature_id: featureId,
            criteria_id: criteriaId,
            verification_type: verificationType,
            evidence: evidenceText,
            passed,
            notes,
            verified_at: result.verification.verifiedAt,
          },
          criterion_status: passed ? 'passed' : 'failed',
          feature_complete: allPassed,
        });
      } catch (error) {
        const errorMessage = error instanceof Error ? error.message : 'Unknown error';
        return errorResponse('verification_error', errorMessage);
      }
    }

    case 'add_evidence': {
      const featureId = args.feature_id as string;
      const criteriaId = args.criteria_id as string;
      const evidenceInput = args.evidence as {
        type: string;
        title?: string;
        description?: string;
        url?: string;
        base64?: string;
        text?: string;
        mimeType?: string;
      };

      try {
        const result = await stateManager.addEvidence({
          featureId,
          criteriaId,
          evidence: {
            type: evidenceInput.type as 'screenshot' | 'video' | 'log' | 'test_result' | 'other',
            title: evidenceInput.title,
            description: evidenceInput.description,
            url: evidenceInput.url,
            base64: evidenceInput.base64,
            text: evidenceInput.text,
            mimeType: evidenceInput.mimeType,
          },
        });

        wsHandler.broadcastFeatureUpdate(sessionId, result.feature);

        return jsonResponse({
          success: true,
          evidence: result.evidence,
          feature_id: featureId,
          criteria_id: criteriaId,
        });
      } catch (error) {
        const errorMessage = error instanceof Error ? error.message : 'Unknown error';
        return errorResponse('add_evidence_error', errorMessage);
      }
    }

    case 'next_feature': {
      // Get session to find current task
      const session = await stateManager.getSession(sessionId);
      if (!session) {
        return errorResponse('session_not_found', `Session ${sessionId} not found`);
      }

      if (!session.taskId) {
        return jsonResponse({
          feature: null,
          message: 'No task set. Link to an Epic and claim a task first.',
          hint: 'Use session_init(epic_id: "EPIC-ID") and then claim a task',
        });
      }

      // Get all features for the current task
      const features = await stateManager.listFeatures(session.taskId);

      // Find first incomplete feature (status !== 'done')
      const incompleteFeature = features.find(f => f.status !== 'done');

      if (incompleteFeature) {
        // Count pending criteria
        const pendingCriteria = incompleteFeature.acceptanceCriteria.filter(
          c => c.status !== 'passed'
        ).length;

        return jsonResponse({
          feature_id: incompleteFeature.id,
          title: incompleteFeature.title,
          description: incompleteFeature.description,
          acceptance_criteria: incompleteFeature.acceptanceCriteria,
          criteria_pending: pendingCriteria,
          criteria_total: incompleteFeature.acceptanceCriteria.length,
        });
      } else {
        return jsonResponse({
          feature: null,
          message: 'All features in current task are complete',
          hint: 'Use complete_task to mark the task done and unlock new tasks',
        });
      }
    }

    case 'get_feature': {
      const featureId = args.feature_id as string;

      const feature = await stateManager.getFeature(featureId);
      if (!feature) {
        return errorResponse('feature_not_found', `Feature ${featureId} not found`);
      }

      return jsonResponse({
        feature: {
          id: feature.id,
          task_id: feature.taskId,
          epic_id: feature.epicId,
          title: feature.title,
          description: feature.description,
          status: feature.status,
          acceptance_criteria: feature.acceptanceCriteria.map(c => ({
            id: c.id,
            description: c.description,
            status: c.status,
            expected_evidence: c.expectedEvidence,
          })),
          assigned_agent: feature.assignedAgent,
          depends_on: feature.dependsOn,
          can_parallelize: feature.canParallelize,
          estimated_complexity: feature.estimatedComplexity,
        },
      });
    }

    case 'submit_evidence': {
      const featureId = args.feature_id as string;
      const criteriaId = args.criteria_id as string;
      const evidenceType = args.evidence_type as EvidenceType;
      const title = args.title as string | undefined;
      const description = args.description as string | undefined;
      const url = args.url as string | undefined;
      const base64 = args.base64 as string | undefined;
      const text = args.text as string | undefined;
      const mimeType = args.mime_type as string | undefined;

      // Validate that at least one content type is provided
      if (!url && !base64 && !text) {
        return errorResponse('missing_content', 'At least one of url, base64, or text must be provided');
      }

      // Get feature to extract epicId and taskId
      const feature = await stateManager.getFeature(featureId);
      if (!feature) {
        return errorResponse('feature_not_found', `Feature ${featureId} not found`);
      }

      // Validate criteria exists
      const criterion = feature.acceptanceCriteria.find(c => c.id === criteriaId);
      if (!criterion) {
        return errorResponse('criteria_not_found', `Criterion ${criteriaId} not found in feature ${featureId}`);
      }

      // Get session for organization context
      const session = await stateManager.getSession(sessionId);
      if (!session || !session.organizationId) {
        return errorResponse('session_error', 'Session not found or missing organization');
      }

      // Parse test results if provided
      const testResultsInput = args.test_results as {
        framework?: string;
        new_tests: { count: number; names?: string[] };
        existing_tests: { count: number; passed: number; failed: number };
        summary: { total: number; passed: number; failed: number; skipped?: number; duration?: number };
      } | undefined;

      const testResults: TestResults | undefined = testResultsInput ? {
        framework: testResultsInput.framework,
        newTests: {
          count: testResultsInput.new_tests.count,
          names: testResultsInput.new_tests.names,
        },
        existingTests: {
          count: testResultsInput.existing_tests.count,
          passed: testResultsInput.existing_tests.passed,
          failed: testResultsInput.existing_tests.failed,
        },
        summary: {
          total: testResultsInput.summary.total,
          passed: testResultsInput.summary.passed,
          failed: testResultsInput.summary.failed,
          skipped: testResultsInput.summary.skipped ?? 0,
          duration: testResultsInput.summary.duration,
        },
      } : undefined;

      try {
        const submission = await stateManager.submitEvidence({
          organizationId: session.organizationId,
          epicId: feature.epicId,
          taskId: feature.taskId,
          featureId,
          criteriaId,
          sessionId,
          type: evidenceType,
          title,
          description,
          url,
          base64,
          text,
          mimeType,
          testResults,
        });

        return jsonResponse({
          success: true,
          submission: {
            id: submission.id,
            type: submission.type,
            title: submission.title,
            review_status: submission.reviewStatus,
            version: submission.version,
            submitted_at: submission.submittedAt,
          },
          feature_id: featureId,
          criteria_id: criteriaId,
          message: 'Evidence submitted for review',
        });
      } catch (error) {
        const errorMessage = error instanceof Error ? error.message : 'Unknown error';
        return errorResponse('submit_evidence_error', errorMessage);
      }
    }

    case 'list_evidence': {
      const featureId = args.feature_id as string;
      const criteriaId = args.criteria_id as string | undefined;
      const reviewStatus = args.review_status as string | undefined;

      try {
        const submissions = await stateManager.listEvidenceSubmissions({
          featureId,
          criteriaId,
          reviewStatus: reviewStatus as 'pending_review' | 'approved' | 'rejected' | 'needs_revision' | undefined,
        });

        return jsonResponse({
          success: true,
          submissions: submissions.map(s => ({
            id: s.id,
            criteria_id: s.criteriaId,
            type: s.type,
            title: s.title,
            description: s.description,
            review_status: s.reviewStatus,
            version: s.version,
            submitted_at: s.submittedAt,
            reviewed_at: s.reviewedAt,
            reviewed_by: s.reviewedBy,
            has_url: !!s.url,
            has_base64: !!s.base64,
            has_text: !!s.text,
          })),
          total: submissions.length,
          feature_id: featureId,
          criteria_id: criteriaId,
        });
      } catch (error) {
        const errorMessage = error instanceof Error ? error.message : 'Unknown error';
        return errorResponse('list_evidence_error', errorMessage);
      }
    }

    case 'upload_evidence_file': {
      const filePath = args.file_path as string;
      const featureId = args.feature_id as string;
      const criteriaId = args.criteria_id as string;
      const title = args.title as string | undefined;
      const description = args.description as string | undefined;
      const evidenceTypeArg = args.evidence_type as EvidenceType | undefined;

      try {
        // SECURITY: Validate path is absolute and doesn't contain traversal
        const normalizedPath = path.normalize(filePath);
        if (!path.isAbsolute(normalizedPath)) {
          return errorResponse(
            'invalid_path',
            'File path must be absolute'
          );
        }

        // SECURITY: Check for path traversal attempts
        if (normalizedPath.includes('..') || filePath.includes('..')) {
          return errorResponse(
            'path_traversal_blocked',
            'Path traversal is not allowed'
          );
        }

        // SECURITY: Block access to sensitive system directories
        // Allow project directories (e.g., /home/user/code/project) but block sensitive files
        const blockedPaths = ['/etc', '/var/log', '/root', '/proc', '/sys'];
        const sensitiveHomePaths = ['.ssh', '.gnupg', '.config', '.local', '.cache', '.npm', '.git/config'];

        const isBlockedPath = blockedPaths.some(blocked =>
          normalizedPath.startsWith(blocked + '/') || normalizedPath === blocked
        );

        // Check for sensitive files within home directories
        const isSensitiveHomePath = sensitiveHomePaths.some(sensitive =>
          normalizedPath.includes(`/${sensitive}/`) || normalizedPath.endsWith(`/${sensitive}`)
        );

        if (isBlockedPath || isSensitiveHomePath) {
          return errorResponse(
            'path_not_allowed',
            'Access to system directories is not allowed'
          );
        }

        // Validate file exists and get stats
        const fileStat = await stat(normalizedPath);
        if (!fileStat.isFile()) {
          return errorResponse('invalid_file', 'Path is not a file');
        }

        // Check file size
        if (fileStat.size > MAX_FILE_SIZE) {
          return errorResponse(
            'file_too_large',
            `File size ${(fileStat.size / 1024 / 1024).toFixed(2)}MB exceeds limit of ${MAX_FILE_SIZE_MB}MB`
          );
        }

        // Determine MIME type
        const mimeType = mimeLookup(normalizedPath) || 'application/octet-stream';
        if (!ALLOWED_MIME_TYPES.includes(mimeType)) {
          return errorResponse(
            'unsupported_file_type',
            `Unsupported file type: ${mimeType}. Allowed: ${ALLOWED_MIME_TYPES.join(', ')}`
          );
        }

        // Get feature to extract context
        const feature = await stateManager.getFeature(featureId);
        if (!feature) {
          return errorResponse('feature_not_found', `Feature ${featureId} not found`);
        }

        // Validate criteria exists
        const criterion = feature.acceptanceCriteria.find(c => c.id === criteriaId);
        if (!criterion) {
          return errorResponse('criteria_not_found', `Criterion ${criteriaId} not found in feature ${featureId}`);
        }

        // Get session for organization context
        const session = await stateManager.getSession(sessionId);
        if (!session || !session.organizationId) {
          return errorResponse('session_error', 'Session not found or missing organization');
        }

        // Auto-detect evidence type if not provided
        const evidenceType = evidenceTypeArg || detectEvidenceType(mimeType);
        // Sanitize filename
        const filename = path.basename(normalizedPath)
          .replace(/[^a-zA-Z0-9._-]/g, '_')
          .substring(0, 255);

        // Read file content
        const content = await readFile(normalizedPath);

        // Step 1: Create evidence submission
        const submission = await stateManager.submitEvidence({
          organizationId: session.organizationId,
          epicId: feature.epicId,
          taskId: feature.taskId,
          featureId,
          criteriaId,
          sessionId,
          type: evidenceType,
          title: title || filename,
          description,
          mimeType,
        });

        // Step 2: Upload file to storage
        const storage = getEvidenceStorage();
        const fileMetadata = await storage.upload({
          organizationId: session.organizationId,
          featureId,
          submissionId: submission.id,
          filename,
          mimeType,
          content,
        });

        return jsonResponse({
          success: true,
          submission: {
            id: submission.id,
            type: submission.type,
            title: submission.title,
            review_status: submission.reviewStatus,
            version: submission.version,
            submitted_at: submission.submittedAt,
          },
          file: {
            id: fileMetadata.id,
            path: fileMetadata.path,
            url: fileMetadata.url,
            mime_type: fileMetadata.mimeType,
            size: fileMetadata.size,
            original_filename: filename,
          },
          feature_id: featureId,
          criteria_id: criteriaId,
          message: 'Evidence file uploaded and submitted for review',
        });
      } catch (error) {
        const errorMessage = error instanceof Error ? error.message : 'Unknown error';

        // SECURITY: Provide helpful error messages without exposing internal paths
        if (errorMessage.includes('ENOENT')) {
          return errorResponse('file_not_found', 'The specified file could not be found');
        }
        if (errorMessage.includes('EACCES')) {
          return errorResponse('file_access_denied', 'Permission denied when accessing the file');
        }

        return errorResponse('upload_evidence_file_error', 'Failed to upload evidence file');
      }
    }

    case 'upload_expected_design': {
      const filePath = args.file_path as string | undefined;
      const base64Content = args.base64 as string | undefined;
      const providedFilename = args.filename as string | undefined;
      const providedMimeType = args.mime_type as string | undefined;
      const featureId = args.feature_id as string;
      const criteriaId = args.criteria_id as string;
      const description = args.description as string;
      const evidenceType = args.evidence_type as string | undefined;
      const isRequired = args.required !== false; // Default to true
      const diffThreshold = args.diff_threshold as number | undefined;

      // Validate input: must have either file_path OR (base64 + filename)
      if (!filePath && !base64Content) {
        return errorResponse('missing_input', 'Either file_path or base64 content must be provided');
      }
      if (base64Content && !providedFilename) {
        return errorResponse('missing_filename', 'filename is required when using base64 content');
      }

      let fileContent: Buffer;
      let filename: string;
      let mimeType: string;

      // MIME type mapping (SVG and HTML excluded for security)
      const mimeTypes: Record<string, string> = {
        '.png': 'image/png',
        '.jpg': 'image/jpeg',
        '.jpeg': 'image/jpeg',
        '.gif': 'image/gif',
        '.webp': 'image/webp',
        '.pdf': 'application/pdf',
        '.json': 'application/json',
        '.txt': 'text/plain',
        '.md': 'text/markdown',
      };

      if (base64Content) {
        // === BASE64 MODE: Content provided directly ===
        try {
          fileContent = Buffer.from(base64Content, 'base64');
        } catch {
          return errorResponse('invalid_base64', 'Invalid base64 encoding');
        }

        // SECURITY: Validate size
        if (fileContent.length > MAX_FILE_SIZE) {
          return errorResponse(
            'file_too_large',
            `Content size ${(fileContent.length / 1024 / 1024).toFixed(2)}MB exceeds limit of ${MAX_FILE_SIZE_MB}MB`
          );
        }

        filename = providedFilename!;
        const ext = path.extname(filename).toLowerCase();
        mimeType = providedMimeType || mimeTypes[ext] || 'application/octet-stream';
      } else {
        // === FILE PATH MODE: Read from filesystem ===
        // SECURITY: Validate path is absolute and doesn't contain traversal
        const normalizedPath = path.normalize(filePath!);
        if (!path.isAbsolute(normalizedPath)) {
          return errorResponse('invalid_path', 'File path must be absolute');
        }

        // SECURITY: Check for path traversal attempts
        if (normalizedPath.includes('..') || filePath!.includes('..')) {
          return errorResponse('path_traversal_blocked', 'Path traversal is not allowed');
        }

        // SECURITY: Block access to sensitive system directories
        const blockedPaths = ['/etc', '/var/log', '/root', '/proc', '/sys'];
        const sensitiveHomePaths = ['.ssh', '.gnupg', '.config', '.local', '.cache', '.npm', '.git/config'];

        const isBlockedPath = blockedPaths.some(blocked =>
          normalizedPath.startsWith(blocked + '/') || normalizedPath === blocked
        );
        const isSensitiveHomePath = sensitiveHomePaths.some(sensitive =>
          normalizedPath.includes(`/${sensitive}/`) || normalizedPath.endsWith(`/${sensitive}`)
        );

        if (isBlockedPath || isSensitiveHomePath) {
          return errorResponse('path_not_allowed', 'Access to system directories is not allowed');
        }

        try {
          // SECURITY: Validate file exists and check size before reading
          const fileStat = await stat(normalizedPath);
          if (!fileStat.isFile()) {
            return errorResponse('invalid_file', 'Path is not a file');
          }

          if (fileStat.size > MAX_FILE_SIZE) {
            return errorResponse(
              'file_too_large',
              `File size ${(fileStat.size / 1024 / 1024).toFixed(2)}MB exceeds limit of ${MAX_FILE_SIZE_MB}MB`
            );
          }

          fileContent = await readFile(normalizedPath);
          filename = path.basename(normalizedPath);
          const ext = path.extname(filename).toLowerCase();
          mimeType = mimeTypes[ext] || 'application/octet-stream';
        } catch (error) {
          const errorMessage = error instanceof Error ? error.message : 'Unknown error';
          if (errorMessage.includes('ENOENT')) {
            return errorResponse('file_not_found', 'The specified file could not be found');
          }
          if (errorMessage.includes('EACCES')) {
            return errorResponse('file_access_denied', 'Permission denied when accessing the file');
          }
          return errorResponse('file_read_error', `Failed to read file: ${errorMessage}`);
        }
      }

      // SECURITY: Validate MIME type is allowed
      if (!ALLOWED_MIME_TYPES.includes(mimeType)) {
        return errorResponse(
          'unsupported_file_type',
          `Unsupported file type: ${mimeType}. Allowed: images (PNG, JPG, GIF, WebP), HTML mocks, videos, PDF, text files`
        );
      }

      try {
        // Auto-detect evidence type from MIME
        const detectedType = evidenceType || (
          mimeType.startsWith('image/') ? 'screenshot' :
          mimeType.startsWith('video/') ? 'video' :
          mimeType === 'text/plain' ? 'log' :
          mimeType === 'application/json' ? 'test_result' :
          'other'
        );

        // Get feature and validate criteria exists
        const feature = await stateManager.getFeature(featureId);
        if (!feature) {
          return errorResponse('feature_not_found', `Feature ${featureId} not found`);
        }

        const criterion = feature.acceptanceCriteria.find(c => c.id === criteriaId);
        if (!criterion) {
          return errorResponse('criteria_not_found', `Criterion ${criteriaId} not found in feature ${featureId}`);
        }

        // Get task and epic for organization info
        const task = await stateManager.getTask(feature.taskId);
        if (!task) {
          return errorResponse('task_not_found', `Task for feature ${featureId} not found`);
        }
        const epic = await stateManager.getEpic(task.epicId);
        if (!epic) {
          return errorResponse('epic_not_found', `Epic for feature ${featureId} not found`);
        }

        // Generate unique ID for this expected evidence
        const expectedEvidenceId = `exp-${Date.now()}-${Math.random().toString(36).substring(2, 8)}`;

        // Upload file to storage with 'expected' prefix
        const storage = getEvidenceStorage();
        const sanitizedFilename = filename.replace(/[^a-zA-Z0-9._-]/g, '_').substring(0, 255);
        const fileMetadata = await storage.upload({
          organizationId: epic.organizationId,
          featureId,
          submissionId: `expected-${expectedEvidenceId}`,
          filename: sanitizedFilename,
          mimeType,
          content: fileContent,
        });

        // Create the expected evidence entry (only include diffThreshold if defined)
        const expectedEvidence: ExpectedEvidence = {
          id: expectedEvidenceId,
          type: detectedType as EvidenceType,
          description,
          required: isRequired,
          referenceUrl: fileMetadata.url,
          ...(diffThreshold !== undefined && { diffThreshold }),
        };

        // Update the criterion with the new expected evidence
        const updatedCriteria = feature.acceptanceCriteria.map(c => {
          if (c.id === criteriaId) {
            return {
              ...c,
              expectedEvidence: [...(c.expectedEvidence || []), expectedEvidence],
            };
          }
          return c;
        });

        // Update the feature
        await stateManager.updateFeature(featureId, {
          acceptanceCriteria: updatedCriteria,
        });

        // Notify via WebSocket - get updated feature and broadcast
        const updatedFeature = await stateManager.getFeature(featureId);
        if (updatedFeature) {
          wsHandler.broadcastFeatureUpdate(sessionId, updatedFeature);
        }

        return jsonResponse({
          expected_evidence: {
            id: expectedEvidenceId,
            type: detectedType,
            description,
            required: isRequired,
            reference_url: fileMetadata.url,
            diff_threshold: diffThreshold,
          },
          file: {
            path: fileMetadata.path,
            url: fileMetadata.url,
            mime_type: fileMetadata.mimeType,
            size: fileMetadata.size,
            original_filename: sanitizedFilename,
          },
          feature_id: featureId,
          criteria_id: criteriaId,
          message: 'Expected design uploaded successfully',
          upload_mode: base64Content ? 'base64' : 'file_path',
        });
      } catch (error) {
        const errorMessage = error instanceof Error ? error.message : 'Unknown error';
        return errorResponse('upload_expected_design_error', `Failed to upload expected design: ${errorMessage}`);
      }
    }

    case 'add_expected_design_url': {
      const referenceUrl = args.reference_url as string;
      const featureId = args.feature_id as string;
      const criteriaId = args.criteria_id as string;
      const description = args.description as string;
      const evidenceType = (args.evidence_type as string) || 'screenshot';
      const isRequired = args.required !== false;
      const diffThreshold = args.diff_threshold as number | undefined;

      // Validate URL format and prevent SSRF
      try {
        const url = new URL(referenceUrl);

        // SECURITY: Only allow HTTPS (and HTTP for dev/test environments)
        const allowedProtocols = ['https:'];
        if (process.env.NODE_ENV !== 'production') {
          allowedProtocols.push('http:');
        }
        if (!allowedProtocols.includes(url.protocol)) {
          return errorResponse('invalid_protocol', `Protocol ${url.protocol} not allowed. Only HTTPS URLs are permitted.`);
        }

        // SECURITY: Block localhost, private IPs, and cloud metadata endpoints
        const hostname = url.hostname.toLowerCase();
        const isBlocked =
          hostname === 'localhost' ||
          hostname === '127.0.0.1' ||
          hostname === '0.0.0.0' ||
          hostname === '169.254.169.254' || // AWS/GCP metadata
          hostname.startsWith('10.') ||
          hostname.startsWith('192.168.') ||
          /^172\.(1[6-9]|2[0-9]|3[0-1])\./.test(hostname);

        if (isBlocked) {
          return errorResponse('ssrf_blocked', 'URLs to internal/private networks are not allowed');
        }
      } catch {
        return errorResponse('invalid_url', 'Invalid URL format for reference_url');
      }

      try {
        // Get feature and validate criteria exists
        const feature = await stateManager.getFeature(featureId);
        if (!feature) {
          return errorResponse('feature_not_found', `Feature ${featureId} not found`);
        }

        const criterion = feature.acceptanceCriteria.find(c => c.id === criteriaId);
        if (!criterion) {
          return errorResponse('criteria_not_found', `Criterion ${criteriaId} not found in feature ${featureId}`);
        }

        // Generate unique ID for this expected evidence
        const expectedEvidenceId = `exp-${Date.now()}-${Math.random().toString(36).substring(2, 8)}`;

        // Create the expected evidence entry (only include diffThreshold if defined)
        const expectedEvidence: ExpectedEvidence = {
          id: expectedEvidenceId,
          type: evidenceType as EvidenceType,
          description,
          required: isRequired,
          referenceUrl,
          ...(diffThreshold !== undefined && { diffThreshold }),
        };

        // Update the criterion with the new expected evidence
        const updatedCriteria = feature.acceptanceCriteria.map(c => {
          if (c.id === criteriaId) {
            return {
              ...c,
              expectedEvidence: [...(c.expectedEvidence || []), expectedEvidence],
            };
          }
          return c;
        });

        // Update the feature
        await stateManager.updateFeature(featureId, {
          acceptanceCriteria: updatedCriteria,
        });

        // Notify via WebSocket - get updated feature and broadcast
        const updatedFeature = await stateManager.getFeature(featureId);
        if (updatedFeature) {
          wsHandler.broadcastFeatureUpdate(sessionId, updatedFeature);
        }

        return jsonResponse({
          expected_evidence: {
            id: expectedEvidenceId,
            type: evidenceType,
            description,
            required: isRequired,
            reference_url: referenceUrl,
            diff_threshold: diffThreshold,
          },
          feature_id: featureId,
          criteria_id: criteriaId,
          message: 'Expected design URL added successfully',
        });
      } catch (error) {
        const errorMessage = error instanceof Error ? error.message : 'Unknown error';
        return errorResponse('add_expected_design_url_error', `Failed to add expected design URL: ${errorMessage}`);
      }
    }

    default:
      return errorResponse('unknown_tool', `Unknown feature tool: ${name}`);
  }
}

