                enum: ['pending', 'passed', 'failed'],
              },
            },
            required: ['id', 'description', 'status'],
          },
          description: 'List of acceptance criteria with their status',
        },
        // Parallel execution fields
        assigned_agent: {
          type: 'string',
          enum: ['designer', 'architect', 'backend-developer', 'frontend-developer', 'data-engineer', 'qa-expert', 'code-reviewer'],
