/**
 * Feature tracking and verification tools
 * Tools for managing features, acceptance criteria, and verification evidence
 */

import { readFile, stat } from 'fs/promises';
import path from 'path';
import { lookup as mimeLookup } from 'mime-types';
import type { ToolDefinition, ToolResponse, ToolDependencies } from '../helpers/types.js';
import { jsonResponse, errorResponse, workflowErrorResponse, validateSessionOrgAccess } from '../helpers/types.js';
import { getCurrentOrgId } from '../helpers/session-context.js';
import type {
  AcceptanceCriteria,
  AgentType,
  TaskComplexity,
  TestResults,
  EvidenceType,
  ExpectedEvidence,
} from '../../state/types.js';
import { detectCircularDependency } from '../helpers/execution-utils.js';
import { getEvidenceStorage } from '../../state/evidence-storage.js';

import { createLogger } from '../../lib/logger.js';

const log = createLogger('mcp-tools');

// File size limit from environment (default 5MB)
// TODO: Make this tier-based in billing epic (1MB free, 10MB paid)
const MAX_FILE_SIZE_MB = parseInt(process.env.EVIDENCE_MAX_FILE_SIZE_MB || '5', 10);
const MAX_FILE_SIZE = MAX_FILE_SIZE_MB * 1024 * 1024;

// Allowed MIME types for evidence uploads
// NOTE: SVG is excluded - can contain embedded scripts (use PNG/WebP instead)
// HTML is allowed but served with CSP headers to prevent script execution
const ALLOWED_MIME_TYPES = [
  // Images (SVG excluded - can contain embedded scripts)
  'image/png', 'image/jpeg', 'image/gif', 'image/webp',
  // Videos
  'video/mp4', 'video/webm', 'video/quicktime',
  // Documents/HTML (for mock files - served with CSP headers)
  'text/html', 'application/xhtml+xml',
  // Text/Logs
  'text/plain', 'text/csv', 'text/markdown', 'application/json',
  // PDF
  'application/pdf',
];

/**
 * Detect evidence type from MIME type
 */
function detectEvidenceType(mimeType: string): EvidenceType {
  if (mimeType.startsWith('image/')) return 'screenshot';
  if (mimeType.startsWith('video/')) return 'video';
  if (mimeType === 'text/plain' || mimeType === 'text/csv') return 'log';
  if (mimeType === 'application/json') return 'test_result';
  return 'other';
}

