        else if (verificationType === 'test_output' || verificationType === 'automated_test') evidenceType = 'test_result';
        else if (verificationType === 'manual_check') evidenceType = 'log';

        const isUrl = evidenceText.startsWith('http://') || evidenceText.startsWith('https://');
