        // Auto-detect evidence type if not provided
        const evidenceType = evidenceTypeArg || detectEvidenceType(mimeType);
        // Sanitize filename
        const filename = path.basename(normalizedPath)
          .replace(/[^a-zA-Z0-9._-]/g, '_')
          .substring(0, 255);

        // Read file content
        const content = await readFile(normalizedPath);

        // Step 1: Create evidence submission
        const submission = await stateManager.submitEvidence({
