/**
 * Quick test script to verify delete_feature tool
 */

import { getApps, deleteApp } from 'firebase-admin/app';
import { FirestoreStateManager } from './server/state/firestore-manager.js';
import * as featureTools from './server/mcp/tools/features.js';
import type { ToolDependencies } from './server/mcp/helpers/types.js';

if (!process.env.FIRESTORE_EMULATOR_HOST) {
  process.env.FIRESTORE_EMULATOR_HOST = '127.0.0.1:8088';
}

async function testDeleteFeature() {
  console.log('Testing delete_feature tool...\n');

  const manager = new FirestoreStateManager();

  const mockWsHandler = {
    broadcastSessionCreated: () => {},
    broadcastFeatureUpdate: () => {},
    broadcastProgressUpdate: () => {},
    broadcastProgressLogged: () => {},
    broadcastInputRequested: () => {},
  };

  try {
    console.log('1. Creating organization...');
    const org = await manager.createOrganization({
      name: 'Test Org',
      slug: 'test-org-' + Date.now(),
    });
    console.log('✓ Organization created:', org.id);

    console.log('\n2. Creating session...');
    const session = await manager.createSession('Test Session', org.id);
    console.log('✓ Session created:', session.id);

    console.log('\n3. Creating epic...');
    const epic = await manager.createEpic({
      organizationId: org.id,
      title: 'Test Epic',
      description: 'Test epic for delete feature',
    });
    console.log('✓ Epic created:', epic.id);

    console.log('\n4. Linking session to epic...');
    await manager.linkSessionToEpic(session.id, epic.id);
    console.log('✓ Session linked to epic');

    console.log('\n5. Creating task...');
    const task = await manager.createTask({
      epicId: epic.id,
      title: 'Test Task',
      description: 'Test task',
    });
    console.log('✓ Task created:', task.id, 'status:', task.status);

    console.log('\n6. Claiming task...');
    await manager.claimTask(session.id, task.id);
    const updatedSession = await manager.getSession(session.id);
    console.log('✓ Task claimed, session.taskId:', updatedSession?.taskId);

    console.log('\n7. Creating feature...');
    const feature = await manager.createFeature({
      taskId: task.id,
      title: 'Test Feature',
      description: 'Test feature to be deleted',
      acceptanceCriteria: [{ description: 'AC 1' }],
    });
    console.log('✓ Feature created:', feature.id);

    const mockDeps: ToolDependencies = {
      stateManager: manager,
      wsHandler: mockWsHandler as any,
      sessionId: session.id,
    };

    console.log('\n8. Testing delete_feature (task in draft status)...');
    const result = await featureTools.handle('delete_feature', { feature_id: feature.id }, mockDeps);
    console.log('Response:', JSON.stringify(JSON.parse(result.content[0].text), null, 2));

    if (!result.isError) {
      console.log('✓ Feature deleted successfully');
    } else {
      console.log('✗ Delete failed');
    }

    console.log('\n9. Verifying feature is soft-deleted...');
    const deletedFeature = await manager.getFeature(feature.id, { includeDeleted: true });
    if (deletedFeature?.deletedAt) {
      console.log('✓ Feature is soft-deleted, deletedAt:', deletedFeature.deletedAt);
    } else {
      console.log('✗ Feature not found or not deleted');
    }

    console.log('\n10. Creating another feature for active task test...');
    const feature2 = await manager.createFeature({
      taskId: task.id,
      title: 'Test Feature 2',
      description: 'Test feature for active task',
      acceptanceCriteria: [{ description: 'AC 1' }],
    });
    console.log('✓ Feature 2 created:', feature2.id);

    console.log('\n11. Setting task to active status...');
    await manager.updateTask(task.id, { status: 'active' });
    const activeTask = await manager.getTask(task.id);
    console.log('✓ Task status:', activeTask?.status);

    console.log('\n12. Testing delete_feature with active task (should fail)...');
    const result2 = await featureTools.handle('delete_feature', { feature_id: feature2.id }, mockDeps);
    console.log('Response:', JSON.stringify(JSON.parse(result2.content[0].text), null, 2));

    if (result2.isError) {
      console.log('✓ Delete correctly rejected for active task');
    } else {
      console.log('✗ Delete should have been rejected');
    }

    console.log('\n✅ All tests passed!');

  } catch (error) {
    console.error('\n❌ Test failed:', error);
  } finally {
    // Cleanup
    for (const app of getApps()) {
      await deleteApp(app);
    }
  }
}

testDeleteFeature();

